var url = require('url');
var request = require('request');
var base_path = 'http://api.douban.com/v2/movie/';


module.exports = Hemera;


function Hemera() {}


Hemera.prototype.getMovies= function(url, callback) {
    
    request(url, function(err, res, body) {
        if (err || res.statusCode !== 200) {
            throw new Error('get movies request failed ' + err + res.statusCode);
        } else {
            body = JSON.parse(body);
            callback(body);
        }
    });
};


Hemera.prototype.getMovieById = function(id, callback) {
    
    request(base_path + 'subject/' + id, function(err, res, body) {
        if (err || res.statusCode !== 200) {
            throw new Error('get movie by id request failed ' + err + res.statusCode);
        } else {
            callback(res, body);
        } 
    });
};


