// 电影条目搜索
Hemera.prototype.search = function(text, callback) {

    var search_path = url.parse('http://api.douban.com/v2/movie/search/');
    
    request({uri: 'http://api.douban.com/v2/movie/search', qs: text}, function(err, res, body) {
        if (err || res.statusCode !== 200) {
            throw new Error('search request failed ' + err + res.statusCode);
        } else {
            body = JSON.parse(body);
            callback(body);
        }
    });
};
